                  li x6, 0x0
                  slli x6, x6, 8
                  addi x6, x6, 0x0
                  sw x6, 0(x20)
                  j main
test_done:        
                  li x20, 0x8ffffff8
                  li x6, 0x0
                  slli x6, x6, 8
                  addi x6, x6, 0x1
                  sw x6, 0(x20)
                  ecall

